import React, { useState, useEffect, useRef } from "react";
import "./App.css";

function App() {
  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([]);
  const [darkMode, setDarkMode] = useState(false);
  const chatEndRef = useRef(null);

  // Auto scroll
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chat]);

  // 🎤 Voice Input
  const startListening = () => {
    const recognition = new window.webkitSpeechRecognition();
    recognition.onresult = (event) => {
      setMessage(event.results[0][0].transcript);
    };
    recognition.start();
  };

  // ⚡ Streaming Effect
  const typeMessage = (text, callback) => {
    let i = 0;
    let current = "";

    const interval = setInterval(() => {
      current += text[i];
      i++;

      callback(current);

      if (i >= text.length) clearInterval(interval);
    }, 20);
  };

  const sendMessage = async () => {
    if (!message) return;

    const userMsg = { role: "user", text: message };
    setChat((prev) => [...prev, userMsg]);

    const res = await fetch("http://localhost:8000/chat", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({ message })
    });

    const data = await res.json();

    let botMsg = { role: "bot", text: "", sources: data.sources };

    setChat((prev) => [...prev, botMsg]);

    typeMessage(data.answer, (typedText) => {
      setChat((prev) => {
        const updated = [...prev];
        updated[updated.length - 1].text = typedText;
        return updated;
      });
    });

    setMessage("");
  };

  // 🌙 Dark mode toggle
  const toggleTheme = () => {
    setDarkMode(!darkMode);
  };

  return (
    <div className={darkMode ? "app dark" : "app"}>

      {/* Sidebar */}
      <div className="sidebar">
        <div className="logo">
          <img src="/logo.png" alt="logo" />
          <h2>NikeBot</h2>
        </div>

        <button className="new-chat">+ New Chat</button>

        <button className="theme-btn" onClick={toggleTheme}>
          {darkMode ? "☀ Light" : "🌙 Dark"}
        </button>

        <div className="recent">
          <p>Recent Chats</p>
          <ul>
            <li>Project overview</li>
            <li>Architecture</li>
          </ul>
        </div>
      </div>

      {/* Chat Area */}
      <div className="chat-container">

        <div className="header">
          <h3>💬 AI Assistant</h3>
          <button className="login-btn">Login (Azure AD)</button>
        </div>

        <div className="chat-box">
          {chat.map((c, i) => (
            <div key={i} className={`msg ${c.role}`}>
              <div className="bubble">
                {c.text}

                {/* 📄 Clickable sources */}
                {c.sources && (
                  <div className="sources">
                    {c.sources.map((s, idx) => (
                      <a key={idx} href="#" target="_blank">
                        {s}
                      </a>
                    ))}
                  </div>
                )}
              </div>
            </div>
          ))}
          <div ref={chatEndRef}></div>
        </div>

        {/* Input */}
        <div className="input-area">
          <button onClick={startListening}>🎤</button>

          <input
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            placeholder="Type your message..."
          />

          <button onClick={sendMessage}>➤</button>
        </div>

      </div>
    </div>
  );
}

export default App;
